import { Component } from "react";
import Seccion from './Seccion'

class Contenido extends Component {
    render(){
        const { secciones } = this.props
        return (
            <div className="contenido">
                {secciones.map(x => 
                    <Seccion key={x} nombre={x}/>    
                )}
            </div>
        )
    }
}

export default Contenido
